// 1. Get the raw text
let rawText = $input.first().json.output;

// 2. Strip markdown code blocks and trim
let cleanJsonString = rawText.replace(/```json\n?|\n?```/g, '').trim();

// 3. Parse JSON
let data = JSON.parse(cleanJsonString);
let testCases = data.test_cases || [];

// 4. Build CSV
const headers = ['ID', 'Test case Title', 'Test Step', 'Test Data', 'Expected Result', 'Jira id'];
let csv = headers.join(',') + '\n';
testCases.forEach(tc => {
  const row = headers.map(h => '"' + String(tc[h] || '').replace(/"/g, '""') + '"');
  csv += row.join(',') + '\n';
});

return [{ json: { csv }, pairedItem: { item: 0 } }];
